#include<bits/stdc++.h>
#define ll long long
#define CI const int
using namespace std;
CI MAXN=6e2+5;int n,w,sum,t[MAXN];
int main(void){
	//freopen("live.in","r",stdin);
	//freopen("live.out","w",stdout);
	scanf("%d%d",&n,&w);
	for(int i=0,x,sum;i<n;++i){
		scanf("%d",&x),++t[x],sum=0;
		for(int j=600;j>=0;--j){
            sum+=t[j];
			if(sum>=max((i+1)*w/100,1)){printf("%d ",j);break;}
		}
	}return false;
}
